;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

[if exp='game.party.hasItem(o.古代語の辞書)']
	@notice text="Written in ancient language, it reads:<r><y>The entrance to the true King's chamber is on the top floor."
[else]
	@notice text="<y>There are characters written on it, but they are in an ancient language and cannot be read."
[endif]

